package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search query with timestamp, IP address, and user agent
	log.Printf("[ANALYTICS] Search: keyword=%q time=%s ip=%s user_agent=%q",
		keyword,
		time.Now().UTC().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
</body>
</html>`

	// Write response
	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

