package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics represents analytics data for a search query
type SearchAnalytics struct {
	Timestamp time.Time `json:"timestamp"`
	Keyword   string    `json:"keyword"`
	IP        string    `json:"ip"`
	UserAgent string    `json:"user_agent"`
	Duration  string    `json:"duration"`
}

// recordAnalytics logs search analytics data
func recordAnalytics(data SearchAnalytics) {
	log.Printf("[ANALYTICS] Keyword=%q IP=%s Time=%s Duration=%s UA=%q",
		data.Keyword,
		data.IP,
		data.Timestamp.Format(time.RFC3339),
		data.Duration,
		data.UserAgent,
	)
}

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	// Extract keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape HTML to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "(no keyword provided)"
	}

	// Record analytics
	analytics := SearchAnalytics{
		Timestamp: time.Now(),
		Keyword:   keyword,
		IP:        r.RemoteAddr,
		UserAgent: r.UserAgent(),
		Duration:  time.Since(start).String(),
	}
	recordAnalytics(analytics)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <div class="search-meta">
        <p>Search completed in ` + time.Since(start).String() + `</p>
    </div>
</body>
</html>`

	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Starting server on :8080")
	log.Println("Example: http://localhost:8080/search?keyword=laptop")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

