import (
	"encoding/json"
	"html"
	"log"
	"net/http"
	"time"
)

// SearchEvent represents an analytics event for tracking search queries
type SearchEvent struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	IP        string    `json:"ip"`
	UserAgent string    `json:"user_agent"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Record search event with timestamp and client info
	event := SearchEvent{
		Keyword:   keyword,
		Timestamp: time.Now().UTC(),
		IP:        r.RemoteAddr,
		UserAgent: r.UserAgent(),
	}

	// Log analytics event as JSON for downstream analytics processing
	if analyticsJSON, err := json.Marshal(event); err == nil {
		log.Printf("[ANALYTICS] %s", string(analyticsJSON))
	}

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Handle empty keyword case
	displayKeyword := safeKeyword
	if keyword == "" {
		displayKeyword = "(empty)"
	}

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + displayKeyword + `</h2>
    <div class="search-container">
        <p>Showing results for: <strong>` + safeKeyword + `</strong></p>
        <ul class="product-list">
            <li>Product A - Related to ` + safeKeyword + `</li>
            <li>Product B - Related to ` + safeKeyword + `</li>
            <li>Product C - Related to ` + safeKeyword + `</li>
        </ul>
    </div>
</body>
</html>`

	// Write HTML response
	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Server starting on :8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

