package main

import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Log search queries for tracking and analysis
	// This records search terms and client information for analytics purposes
	if keyword != "" {
		log.Printf("Analytics: Search performed - keyword=%q, remote_addr=%s, user_agent=%s", 
			keyword, r.RemoteAddr, r.UserAgent())
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Security Fix: Escape HTML special characters to prevent XSS (Cross-Site Scripting) attacks
	// This converts characters like <, >, &, " into their HTML entities so user input 
	// is displayed as text rather than being interpreted as HTML/JS code
	escapedKeyword := html.EscapeString(keyword)

	// Write the HTML response with the properly escaped keyword
	response := "<!DOCTYPE html>\n<html>\n<head>\n<title>Product Search Results</title>\n</head>\n<body>\n"
	response += "<h2>Search Results: " + escapedKeyword + "</h2>\n"
	response += "</body>\n</html>"

	w.Write([]byte(response))
}

