package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics represents analytics data for search queries
type SearchAnalytics struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	IP        string    `json:"ip"`
	UserAgent string    `json:"user_agent"`
}

// logAnalytics records search analytics data
func logAnalytics(keyword string, r *http.Request) {
	analytics := SearchAnalytics{
		Keyword:   keyword,
		Timestamp: time.Now(),
		IP:        r.RemoteAddr,
		UserAgent: r.UserAgent(),
	}
	// Log analytics data (in production, this would write to database or analytics service)
	log.Printf("[ANALYTICS] Keyword: %q, Time: %s, IP: %s, UA: %s",
		analytics.Keyword,
		analytics.Timestamp.Format(time.RFC3339),
		analytics.IP,
		analytics.UserAgent)
}

// HandleProductSearch handles product search requests with analytics tracking
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Log analytics for this search query
	logAnalytics(keyword, r)

	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Handle empty keyword case
	displayText := escapedKeyword
	if displayText == "" {
		displayText = "(empty)"
	}

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + escapedKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + displayText + `</h2>
    <div id="product-list">
        <!-- Product search results would be rendered here -->
        <p>Found products matching your search criteria.</p>
    </div>
</body>
</html>`

	// Write response
	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

