	analyticsMutex sync.Mutex
)

// HandleProductSearch handles product search requests with analytics tracking.
// It expects a "keyword" query parameter and returns HTML displaying the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Record analytics data
	recordAnalytics(keyword, r)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "(empty)"
	}

	// Generate HTML response
	htmlContent := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
    <style>
