        <p>Displaying products matching your search criteria.</p>
    </div>
</body>
</html>`

	// Write response
	w.WriteHeader(http.StatusOK)
	w.Write([]byte(htmlContent))
}

// recordAnalytics logs search query data for analytics purposes
func recordAnalytics(keyword string, r *http.Request) {
	data := AnalyticsData{
		Keyword:   keyword,
		Timestamp: time.Now(),
		RemoteIP:  r.RemoteAddr,
		UserAgent: r.UserAgent(),
	}

	// Thread-safe storage
	analyticsMutex.Lock()
	analyticsStore = append(analyticsStore, data)
	analyticsMutex.Unlock()

	// Log to stdout for real-time monitoring
	log.Printf("[ANALYTICS] Search: %q | Time: %s | IP: %s | UserAgent: %s",
		keyword,
		data.Timestamp.Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
	)
}

func main() {
