// HandleProductSearch handles product search requests and logs analytics data.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the search keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Record search event with timestamp, IP, and user agent
	timestamp := time.Now().UTC()
	clientIP := r.RemoteAddr
	userAgent := r.UserAgent()

	// Log analytics data for monitoring and analysis
	log.Printf("[ANALYTICS] event=search timestamp=%s keyword=%q ip=%s user_agent=%q",
		timestamp.Format(time.RFC3339),
		keyword,
		clientIP,
		userAgent,
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Generate HTML response with the search keyword in the title
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
</body>
</html>`

	// Write the HTML response
	w.Write([]byte(htmlResponse))
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

