import (
	"html"
	"log"
	"net/http"
	"sync"
	"time"
)

// SearchEvent represents a single search analytics event
type SearchEvent struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	IP        string    `json:"ip"`
	UserAgent string    `json:"user_agent"`
}

// AnalyticsCollector provides thread-safe storage for search analytics
type AnalyticsCollector struct {
	mu     sync.RWMutex
	events []SearchEvent
}

// Record logs a search event to the analytics store
func (ac *AnalyticsCollector) Record(keyword, ip, userAgent string) {
	ac.mu.Lock()
	defer ac.mu.Unlock()

	event := SearchEvent{
		Keyword:   keyword,
		Timestamp: time.Now(),
		IP:        ip,
		UserAgent: userAgent,
	}
	ac.events = append(ac.events, event)

	// Log to stdout for real-time monitoring
	log.Printf("[Analytics] Search keyword=%q ip=%s time=%s", keyword, ip, event.Timestamp.Format(time.RFC3339))
}

var analytics = &AnalyticsCollector{
	events: make([]SearchEvent, 0),
}

// HandleProductSearch handles product search requests with analytics tracking
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Record analytics data
	analytics.Record(keyword, r.RemoteAddr, r.UserAgent())

	// Escape HTML to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "(empty)"
	}

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 800px; margin: 50px auto; padding: 0 20px; }
        .search-info { color: #666; margin-top: 20px; }
    </style>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <div class="search-info">
        <p>Search completed successfully.</p>
        <p><small>Timestamp: ` + time.Now().Format("2006-01-02 15:04:05") + `</small></p>
    </div>
</body>
</html>`

	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Server starting on http://localhost:8080")
	log.Println("Example usage: http://localhost:8080/search?keyword=laptop")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

