func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Record start time for performance analytics
	startTime := time.Now()

	// Extract search keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Prepare analytics data structure
	analyticsData := struct {
		Timestamp    time.Time `json:"timestamp"`
		Keyword      string    `json:"keyword"`
		IP           string    `json:"ip"`
		UserAgent    string    `json:"user_agent"`
		Referer      string    `json:"referer"`
		Method       string    `json:"method"`
		ResponseTime string    `json:"response_time"`
	}{
		Timestamp: time.Now(),
		Keyword:   keyword,
		IP:        r.RemoteAddr,
		UserAgent: r.UserAgent(),
		Referer:   r.Referer(),
		Method:    r.Method,
	}

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "No keyword provided"
	}

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response
	htmlContent := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
</body>
</html>`

	// Write response
	w.Write([]byte(htmlContent))

	// Calculate response time and log analytics
	elapsed := time.Since(startTime)
	analyticsData.ResponseTime = elapsed.String()

	// Marshal and log analytics data
	analyticsJSON, err := json.Marshal(analyticsData)
	if err == nil {
		log.Printf("Search Analytics: %s", string(analyticsJSON))
	}
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

