// SearchAnalytics represents a search analytics event
type SearchAnalytics struct {
	Keyword   string    `json:"keyword"`
	IP        string    `json:"ip"`
	UserAgent string    `json:"user_agent"`
	Timestamp time.Time `json:"timestamp"`
	Referer   string    `json:"referer"`
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only accept GET requests
	if r.Method != http.MethodGet {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Record search event
	event := SearchAnalytics{
		Keyword:   keyword,
		IP:        r.RemoteAddr,
		UserAgent: r.UserAgent(),
		Timestamp: time.Now().UTC(),
		Referer:   r.Referer(),
	}

	// Log analytics as JSON for downstream processing
	analyticsJSON, err := json.Marshal(event)
	if err == nil {
		log.Printf("[ANALYTICS] %s", string(analyticsJSON))
	}

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "(empty)"
	}

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 1200px; margin: 0 auto; padding: 20px; }
        h2 { color: #333; border-bottom: 2px solid #007bff; padding-bottom: 10px; }
        .search-info { background: #f8f9fa; padding: 15px; border-radius: 5px; margin-top: 20px; }
    </style>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <div class="search-info">
        <p>Displaying product results for your search query.</p>
        <p><small>Search tracked for analytics purposes.</small></p>
    </div>
</body>
</html>`

	// Write response
	w.WriteHeader(http.StatusOK)
	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	addr := ":8080"
	log.Printf("Starting product search server with analytics support on %s", addr)
	log.Printf("Example usage: http://localhost%s/search?keyword=laptop", addr)

	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

