package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests and logs analytics data.
// It extracts the 'keyword' query parameter, sanitizes it for HTML output,
// records analytics, and returns an HTML page with the search results title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Sanitize keyword to prevent XSS attacks when rendering in HTML
	safeKeyword := html.EscapeString(keyword)

	// Record analytics for this search request
	recordSearchAnalytics(r, keyword)

	// Set Content-Type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate HTML response with the required format
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: %s</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <div class="search-meta">
        <p>Search query: <strong>%s</strong></p>
    </div>
    <div class="results-container">
        <!-- Product results would be dynamically loaded here -->
        <p>No products found matching your search criteria.</p>
    </div>
</body>
</html>`, safeKeyword, safeKeyword, safeKeyword)

	// Write the HTML response
	w.Write([]byte(htmlContent))
}

// recordSearchAnalytics logs search analytics including timestamp, 
// keyword, client IP, and user agent for tracking purposes.
func recordSearchAnalytics(r *http.Request, keyword string) {
	timestamp := time.Now().UTC().Format(time.RFC3339)
	clientIP := r.RemoteAddr
	userAgent := r.UserAgent()
	referer := r.Referer()

	log.Printf("[ANALYTICS] timestamp=%s keyword=%q ip=%s user_agent=%q referer=%q",
		timestamp, keyword, clientIP, userAgent, referer)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Server starting on http://localhost:8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

