package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search event with timestamp and client info
	log.Printf(`{"type":"search_analytics","keyword":%q,"timestamp":%q,"remote_addr":%q,"user_agent":%q}`,
		keyword,
		time.Now().UTC().Format(time.RFC3339),
		r.RemoteAddr,
		r.UserAgent(),
	)

	// Set HTML content type
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)
	if safeKeyword == "" {
		safeKeyword = "(empty search)"
	}

	// Generate HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        h2 { color: #333; border-bottom: 2px solid #007bff; padding-bottom: 10px; }
        .results { margin-top: 20px; }
    </style>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <div class="results">
        <p>Displaying products matching your search query...</p>
    </div>
</body>
</html>`

	w.Write([]byte(htmlResponse))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	log.Println("Starting product search server on :8080")
	log.Println("Example: http://localhost:8080/search?keyword=laptop")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

