package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests and logs analytics.
// It expects a 'keyword' query parameter and returns an HTML page displaying
// the search results title with the keyword.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search query with timestamp, remote address, and user agent
	// This supports monitoring search trends and user behavior analysis
	log.Printf("[ANALYTICS] timestamp=%s keyword=%q remote_addr=%s user_agent=%q method=%s",
		time.Now().UTC().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent(),
		r.Method,
	)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Generate HTML response with the required format
	response := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: ` + safeKeyword + `</title>
</head>
<body>
    <h2>Search Results: ` + safeKeyword + `</h2>
    <p>Displaying results for your search query.</p>
</body>
</html>`

	// Write response
	w.Write([]byte(response))
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start server
	addr := ":8080"
	log.Printf("Starting product search server on %s", addr)
	log.Fatal(http.ListenAndServe(addr, nil))
}

